from funasr import AutoModel
from pathlib import Path
from typing_extensions import Any

from uiya._dataclass import ConfigParser
from uiya._typing import AutoModelResponse


class FunASRModel:

    def __init__(self):
        """ """
        self.config = ConfigParser()
        self.base_model: str = self.config.base_model
        self.vad_model: str = self.config.vad_model
        self.punc_model: str = self.config.punc_model
        self.device: str = self.config.device

    def full_version(self):
        model = AutoModel(
            model=self.base_model,  # base
            vad_model=self.vad_model,  # 检测语音活动，自动分隔
            punc_model=self.punc_model,  # 给出标点。
            # model_revision="v2.0.4",
            device=self.device,
        )
        return model

    def only_vad(self):
        model = AutoModel(model=self.vad_model, device=self.device)
        return model

    def only_txt(self):
        model = AutoModel(model=self.base_model, device=self.device)
        return model

    def only_puc(self):
        model = AutoModel(model=self.punc_model, device=self.device)
        return model


